<?php
 namespace League\CommonMark\Extension\TableOfContents\Normalizer; use League\CommonMark\Block\Element\ListBlock; use League\CommonMark\Block\Element\ListItem; use League\CommonMark\Extension\TableOfContents\Node\TableOfContents; final class RelativeNormalizerStrategy implements NormalizerStrategyInterface { private $toc; private $listItemStack = []; public function __construct(TableOfContents $toc) { $this->toc = $toc; } public function addItem(int $level, ListItem $listItemToAdd): void { \end($this->listItemStack); $previousLevel = \key($this->listItemStack); while ($previousLevel !== null && $level < $previousLevel) { array_pop($this->listItemStack); \end($this->listItemStack); $previousLevel = \key($this->listItemStack); } $lastListItem = \current($this->listItemStack); if ($lastListItem !== false && $level > $previousLevel) { $targetListBlock = new ListBlock($lastListItem->getListData()); $targetListBlock->setStartLine($listItemToAdd->getStartLine()); $targetListBlock->setEndLine($listItemToAdd->getEndLine()); $lastListItem->appendChild($targetListBlock); } elseif ($lastListItem === false) { $targetListBlock = $this->toc; } else { $targetListBlock = $lastListItem->parent(); } $targetListBlock->appendChild($listItemToAdd); $this->listItemStack[$level] = $listItemToAdd; } } \class_exists(TableOfContents::class); 